def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[idx] = np.inf
            continue
        value = 0.0
        factor = 1.5
        modifier = 1.0
        complexity = 0.0
        adjustment = 1.0
        steps = 15
        for step in range(1, steps + 1):
            sqr = step * step
            ratio = item / (capacity + 1e-6)
            mod_step = ((step % 4) + 1) * 0.15
            if step % 2 == 0:
                factor *= 1 + 0.03 * np.cos(step + capacity)
            else:
                factor *= 1 - 0.02 * np.sin(step * 0.7)
            if ratio < step / steps:
                val_inc = np.tanh((capacity % (step+1) + 1) / (item + 1)) * factor * sqr
                value += val_inc
            else:
                val_inc = (np.log(capacity + step + 1) + np.sqrt((item + 1)/ (step+1))) / (sqr + 1) * factor
                value += val_inc
            if step % 5 == 0:
                complexity += np.exp(-abs(capacity - item * step)) * 0.5
            else:
                complexity -= np.log1p(abs(capacity % (step + 3) - item % (step + 2)))
            if step in {3, 7, 11}:
                multiplier = 1.0
                for sub in range(1, 5):
                    diff = capacity - item * sub * sub
                    if diff > 0 and diff % (sub+1) == 0:
                        multiplier += np.sqrt(diff) / (sub + 2)
                    else:
                        multiplier -= abs(diff) ** 1.1 / (sub + 3)
                adjustment *= multiplier
            if (capacity * step) % 8 == 0:
                adjustment *= 1 + 0.04
            if capacity % 3 == 0 and step % 3 == 1:
                complexity += np.sin(ratio * step) * 0.3
            if ratio > 0.9 and step % 2 == 1:
                adjustment *= 1 + 0.05 * step
            if ratio < 0.1 and step % 4 == 2:
                adjustment *= 0.85
            if capacity > item * 3:
                value += np.log1p(capacity) * 0.4
            else:
                value -= np.sqrt(item) * 0.3
        value += complexity * 0.7
        value *= adjustment
        if value < 0:
            priority_score = -value * (np.sqrt(capacity) + ratio)
        else:
            priority_score = -value / (capacity + 2) * (1 + ratio ** 2)
        if capacity % 2 == 0:
            priority_score *= 0.97
        else:
            priority_score *= 1.03
        if ratio > 0.8:
            priority_score *= 1.2
        elif ratio < 0.15:
            priority_score *= 0.8
        if priority_score > 1000:
            priority_score = 1000
        elif priority_score < -1000:
            priority_score = -1000
        priorities[idx] = priority_score
    return priorities
